import React, { useEffect, useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import api from '../utils/api';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user';
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    if (!user || isStaff) return;
    const fetchUnread = () => {
      api.get('/announcements/unread-count').then(r => setUnreadCount(r.data.count || 0)).catch(() => {});
    };
    fetchUnread();
    const id = setInterval(fetchUnread, 60000);
    return () => clearInterval(id);
  }, [user, isStaff]);

  const sections: { title: string; items: { path: string; label: string; show: boolean; badge?: number }[] }[] = [
    {
      title: 'Overview',
      items: [
        { path: '/dashboard',   label: 'Dashboard',   show: true },
      ],
    },
    {
      title: 'Catalogue',
      items: [
        { path: '/books',       label: 'Books',       show: true },
        { path: '/categories',  label: 'Categories',  show: true },
      ],
    },
    {
      title: 'Circulation',
      items: [
        { path: '/borrows',     label: 'Borrows',          show: isStaff },
        { path: '/requests',    label: 'Borrow Requests',  show: isStaff },
        { path: '/my-borrows',  label: 'My Library',       show: !isStaff },
      ],
    },
    {
      title: 'People',
      items: [
        { path: '/members',          label: 'Members',         show: isStaff },
        { path: '/create-assistant', label: 'Add Assistant',   show: user?.role === 'librarian' },
      ],
    },
    {
      title: 'Communication',
      items: [
        { path: '/announcements', label: 'Announcements', show: true, badge: isStaff ? 0 : unreadCount },
      ],
    },
  ];

  const roleLabel: Record<string,string> = {
    librarian: 'Head Librarian',
    library_assistant: 'Asst. Librarian',
    student: 'Student',
    staff: 'Staff Member',
  };

  return (
    <>
      <style>{`
        .nav-lnk {
          display: flex; align-items: center; justify-content: space-between; gap: 8px;
          padding: 7px 10px; border-radius: 6px;
          font-size: 13.5px; font-weight: 500;
          color: var(--sidebar-text); text-decoration: none;
          margin-bottom: 1px;
          transition: background .1s, color .1s;
        }
        .nav-lnk:hover { background: var(--bg3); color: var(--sidebar-text-hover); }
        .nav-lnk.active {
          background: var(--sidebar-active-bg);
          color: var(--sidebar-active-text);
          font-weight: 600;
        }
        .nav-lnk .nav-badge {
          background: var(--accent);
          color: #fff;
          font-size: 10.5px; font-weight: 600;
          padding: 1px 6px; border-radius: 99px;
          line-height: 1.4; min-width: 18px; text-align: center;
        }
        .so-btn:hover { background: var(--bg3) !important; color: var(--danger) !important; border-color: var(--border-strong) !important; }
      `}</style>

      <aside style={{
        width: 240, minHeight: '100vh',
        background: 'var(--sidebar-bg)',
        borderRight: '1px solid var(--sidebar-border)',
        display: 'flex', flexDirection: 'column', flexShrink: 0
      }}>

        {/* Brand */}
        <div style={{ padding: '18px 18px 14px', borderBottom: '1px solid var(--sidebar-border)' }}>
          <div style={{ display:'flex', alignItems:'center', gap:9 }}>
            <div style={{
              width: 28, height: 28, borderRadius: 7,
              background: '#18181b', color: '#fff',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 13, fontWeight: 700, letterSpacing: '-0.3px'
            }}>L</div>
            <div>
              <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text)', letterSpacing: '-0.2px' }}>
                LibraryMS
              </div>
              <div style={{ fontSize: 10.5, color: 'var(--text-muted)', marginTop: 1 }}>
                BAUST · University Library
              </div>
            </div>
          </div>
        </div>

        {/* Nav */}
        <nav style={{ flex: 1, padding: '14px 10px', overflowY: 'auto' }}>
          {sections.map(section => {
            const visible = section.items.filter(i => i.show);
            if (!visible.length) return null;
            return (
              <div key={section.title} style={{ marginBottom: 14 }}>
                <div style={{
                  fontSize: 10.5, fontWeight: 600, color: 'var(--nav-section-color)',
                  letterSpacing: '0.06em', textTransform: 'uppercase',
                  padding: '0 10px 6px'
                }}>
                  {section.title}
                </div>
                {visible.map(item => (
                  <NavLink key={item.path} to={item.path}
                    className={({ isActive }) => `nav-lnk${isActive ? ' active' : ''}`}>
                    <span>{item.label}</span>
                    {(item.badge ?? 0) > 0 && <span className="nav-badge">{item.badge}</span>}
                  </NavLink>
                ))}
              </div>
            );
          })}
        </nav>

        {/* User */}
        <div style={{ padding: '12px 12px 14px', borderTop: '1px solid var(--sidebar-border)' }}>
          <div style={{ display:'flex', alignItems:'center', gap:10, padding:'4px 4px 10px' }}>
            <div style={{
              width: 32, height: 32, borderRadius: '50%',
              background: '#18181b', color: '#fff',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontWeight: 600, fontSize: 13, flexShrink: 0
            }}>
              {user?.name?.charAt(0).toUpperCase()}
            </div>
            <div style={{ minWidth: 0, flex: 1 }}>
              <div style={{
                fontSize: 13, fontWeight: 600, color: 'var(--text)',
                overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap'
              }}>
                {user?.name}
              </div>
              <div style={{ fontSize: 11.5, color: 'var(--text-muted)', marginTop: 1 }}>
                {roleLabel[user?.role || ''] || user?.role}
                {user?.member_id && <span className="mono"> · {user.member_id}</span>}
              </div>
            </div>
          </div>
          <button className="so-btn"
            onClick={() => { logout(); navigate('/login'); }}
            style={{
              width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center',
              padding: '7px', borderRadius: 7,
              fontSize: 12.5, fontWeight: 500,
              color: 'var(--text-dim)',
              background: 'var(--bg2)',
              border: '1px solid var(--border)',
              cursor: 'pointer', fontFamily: 'inherit',
              transition: 'all .12s'
            }}>
            Sign out
          </button>
        </div>
      </aside>
    </>
  );
}
